#include <bits/stdc++.h>
using namespace std;
const int maxn=5e5+5;
vector<int> e[maxn];
int t,n,m;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	while(t--) {
		cin>>n>>m;
		fill(e+1,e+n+2,e[0]);
		for(int i=1,x,y;i<=m;i++){
			cin>>x>>y;
			e[x].emplace_back(y);
		}
		for(int i=1; i<=n; i++) {
			sort(e[i].begin(),e[i].end());
			for(int x:e[i]) {
				cout<<x<<" ";
			}
			cout<<"\n";
		}
	}
	return 0;
}
